import{c as s,Q as n,j as e,m as p}from"./chunks/framework.iD28w_5a.js";const u=JSON.parse('{"title":"011-big-kernel-pic-irq-1 · PIC 与 IRQ","description":"","frontmatter":{"title":"011-big-kernel-pic-irq-1 · PIC 与 IRQ"},"headers":[],"relativePath":"hands-on/011-big-kernel-pic-irq-1.md","filePath":"hands-on/011-big-kernel-pic-irq-1.md","lastUpdated":1779686691000}'),l={name:"hands-on/011-big-kernel-pic-irq-1.md"};function i(t,a,o,c,r,I){return n(),e("div",null,[...a[0]||(a[0]=[p(`<h1 id="_011-pic-重映射-pit-定时器-irq-中断-一-pic-驱动-——-让内核拥有时间感" tabindex="-1">011 PIC 重映射 + PIT 定时器 + IRQ 中断（一）：PIC 驱动 —— 让内核拥有时间感 <a class="header-anchor" href="#_011-pic-重映射-pit-定时器-irq-中断-一-pic-驱动-——-让内核拥有时间感" aria-label="Permalink to &quot;011 PIC 重映射 + PIT 定时器 + IRQ 中断（一）：PIC 驱动 —— 让内核拥有时间感&quot;">​</a></h1><h2 id="章节导语" tabindex="-1">章节导语 <a class="header-anchor" href="#章节导语" aria-label="Permalink to &quot;章节导语&quot;">​</a></h2><p>上一章（010）我们给大内核装上了 GDT、IDT 和 CPU 异常处理，用 <code>int $3</code> 验证了整条链路能正常工作。但说实话，目前这个内核还只是一个&quot;只会接 CPU 异常电话&quot;的系统，外部世界的任何事件它都听不到——定时器在嘀嗒、键盘在按键、磁盘在读写，CPU 对这些一无所知，因为我们根本没配置硬件中断的入口。</p><p>这一章我们要做的是把硬件中断（IRQ）真正接进来。具体来说，我们需要配置 8259A PIC（可编程中断控制器），把 IRQ0-15 重映射到 IDT 的空闲向量区域（0x20-0x2F），然后配置 PIT（可编程间隔定时器）让它每秒产生 100 次中断（100 Hz），最后写一个 IRQ0 处理函数来统计 tick 并每秒在串口打印一行 <code>[TICK] uptime: Ns</code>。完成本章后，你会看到 QEMU 串口每秒稳定地输出一行 uptick 信息——这意味着我们的内核第一次有了&quot;时间感&quot;，第一次能对外部硬件事件做出响应。</p><p>本章分为三篇，本篇（第一篇）聚焦于 PIC 驱动的设计与实现。第二篇覆盖 PIT 定时器驱动，第三篇完成 IRQ stub 注册、路由表和 kernel_main 的集成。</p><p>本章的前置知识是上一章（010_big_kernel_gdt_idt）的 GDT/IDT/ISR 基础设施。你需要理解 IDT 的 set_handler 机制、ISR stub 的工作流程、以及 <code>InterruptFrame</code> 的布局。如果你还没读完 010，建议先回去补完。</p><hr><h2 id="概念精讲" tabindex="-1">概念精讲 <a class="header-anchor" href="#概念精讲" aria-label="Permalink to &quot;概念精讲&quot;">​</a></h2><h3 id="_8259a-pic-x86-外部中断的-前台接待" tabindex="-1">8259A PIC：x86 外部中断的&quot;前台接待&quot; <a class="header-anchor" href="#_8259a-pic-x86-外部中断的-前台接待" aria-label="Permalink to &quot;8259A PIC：x86 外部中断的&quot;前台接待&quot;&quot;">​</a></h3><p>在 x86 架构里，CPU 并不是直接和每个外部设备打交道的。外部设备（键盘、定时器、磁盘等）产生的中断信号先到达一个叫做 PIC（Programmable Interrupt Controller，可编程中断控制器）的芯片，PIC 收到信号后做两件事：一是根据优先级决定哪个中断应该先处理（IRQ0 优先级最高，IRQ7 最低），二是把中断请求转换成一个向量号发送给 CPU。CPU 收到这个向量号之后，就去 IDT 里查对应的处理程序——这个过程和我们上一章处理 CPU 异常的流程完全一样，唯一的区别是触发源从&quot;CPU 内部异常&quot;变成了&quot;外部硬件中断&quot;。</p><p>PC 兼容机上有两片 8259A PIC 芯片，以级联（cascade）方式连接——Master PIC 负责处理 IRQ0-7，Slave PIC 负责处理 IRQ8-15，Slave 通过 Master 的 IRQ2 线路级联上去。这套设计是 IBM PC/AT 时代留下来的遗产，虽然现代系统早就用 APIC 替代了 8259A，但在 QEMU 的默认配置里 8259A 仍然存在且可用，对于教学目的来说完全够用。</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>硬件中断的传递路径：</span></span>
<span class="line"><span></span></span>
<span class="line"><span>外部设备 → IRQ 线路 → PIC → INTR 信号 → CPU → 查 IDT[向量号] → 跳转到 ISR stub → C handler</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Master PIC (IRQ0-7) 的级联拓扑：</span></span>
<span class="line"><span>                ┌──────────────────────────────────────────┐</span></span>
<span class="line"><span>  PIT Timer ──→ │ IRQ0                                     │</span></span>
<span class="line"><span>  Keyboard ───→ │ IRQ1                                     │</span></span>
<span class="line"><span>                │ IRQ2 ←── Slave PIC (IRQ8-15)            │ → CPU INTR</span></span>
<span class="line"><span>  COM2 ──────→ │ IRQ3                                     │</span></span>
<span class="line"><span>  COM1 ──────→ │ IRQ4                                     │</span></span>
<span class="line"><span>  ...          │ IRQ5, IRQ6, IRQ7                         │</span></span>
<span class="line"><span>                └──────────────────────────────────────────┘</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Slave PIC (IRQ8-15):</span></span>
<span class="line"><span>  RTC ──────→  │ IRQ8-15                                 │ → Master IRQ2</span></span>
<span class="line"><span>  ...</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br><span class="line-number">15</span><br><span class="line-number">16</span><br><span class="line-number">17</span><br></div></div><p>这里有一个非常重要的问题需要解决——BIOS 默认把 Master PIC 的 IRQ0-7 映射到 INT 0x08-0x0F，Slave PIC 的 IRQ8-15 映射到 INT 0x70-0x77。这个映射和 CPU 的异常向量号冲突了——INT 0x08 是 #DF（Double Fault），INT 0x0E 是 #PF（Page Fault），如果 IRQ 不重映射的话，定时器中断一来，CPU 以为发生了 Double Fault，直接跳到 Double Fault 处理函数去了。所以 PIC 初始化的核心任务就是把 IRQ 重映射到 IDT 里空闲的区域——习惯上用 0x20-0x2F（也就是 IDT 的 32-47 号条目），因为 Intel 保留了 0-31 给 CPU 异常，32 开始就是自由使用的。</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>PIC 重映射前后的向量号对照：</span></span>
<span class="line"><span></span></span>
<span class="line"><span>重映射前（BIOS 默认，会冲突！）：</span></span>
<span class="line"><span>  IRQ0 → INT 0x08  ← 和 #DF 冲突！</span></span>
<span class="line"><span>  IRQ1 → INT 0x09  ← 和 #DB 冲突！</span></span>
<span class="line"><span>  ...</span></span>
<span class="line"><span>  IRQ7 → INT 0x0F</span></span>
<span class="line"><span>  IRQ8 → INT 0x70</span></span>
<span class="line"><span>  ...</span></span>
<span class="line"><span></span></span>
<span class="line"><span>重映射后（本章的配置，安全）：</span></span>
<span class="line"><span>  IRQ0 → INT 0x20  (vector 32)</span></span>
<span class="line"><span>  IRQ1 → INT 0x21  (vector 33)</span></span>
<span class="line"><span>  ...</span></span>
<span class="line"><span>  IRQ7 → INT 0x27  (vector 39)</span></span>
<span class="line"><span>  IRQ8 → INT 0x28  (vector 40)</span></span>
<span class="line"><span>  ...</span></span>
<span class="line"><span>  IRQ15 → INT 0x2F (vector 47)</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br><span class="line-number">15</span><br><span class="line-number">16</span><br><span class="line-number">17</span><br><span class="line-number">18</span><br></div></div><h3 id="icw1-icw4-pic-初始化的四次-握手" tabindex="-1">ICW1-ICW4：PIC 初始化的四次&quot;握手&quot; <a class="header-anchor" href="#icw1-icw4-pic-初始化的四次-握手" aria-label="Permalink to &quot;ICW1-ICW4：PIC 初始化的四次&quot;握手&quot;&quot;">​</a></h3><p>8259A 的初始化过程是一个固定的四步序列，叫做 ICW（Initialization Command Word）。每一步往 PIC 的 I/O 端口写一个字节，PIC 内部状态机按顺序接收。这四步分别是：</p><ul><li><strong>ICW1</strong>：告诉 PIC &quot;我要开始初始化了&quot;，同时指明是否级联模式、是否需要 ICW4。我们写 <code>0x11</code>（INIT=1, ICW4 needed=1, cascade mode）。</li><li><strong>ICW2</strong>：设置向量号基址。Master 写 <code>0x20</code>，Slave 写 <code>0x28</code>。这一步决定了 IRQ0 会映射到 INT 0x20、IRQ1 到 INT 0x21，以此类推。</li><li><strong>ICW3</strong>：告诉两片 PIC 级联拓扑。Master 写 <code>0x04</code>（表示 IRQ2 上接了 Slave），Slave 写 <code>0x02</code>（表示自己连在 Master 的 IRQ2 线路上）。</li><li><strong>ICW4</strong>：设置工作模式。我们写 <code>0x01</code>（8086 模式，不用 auto-EOI，不用 buffered mode）。</li></ul><p>一个很关键的细节是——8259A 的数据手册要求两次连续的 I/O 写入之间有一定的延迟（因为这是 ISA 总线时代的芯片，时序很慢）。我们在每次 <code>io_outb</code> 之后调用一次 <code>io_wait()</code>（往端口 0x80 写一个字节，大约 1 微秒的延迟），来满足这个时序要求。如果你的 PIC 初始化之后行为异常（比如该来的中断不来、EOI 发了没反应），第一个要检查的就是有没有漏掉 <code>io_wait()</code>。</p><h3 id="eoi-中断结束的-签收单" tabindex="-1">EOI：中断结束的&quot;签收单&quot; <a class="header-anchor" href="#eoi-中断结束的-签收单" aria-label="Permalink to &quot;EOI：中断结束的&quot;签收单&quot;&quot;">​</a></h3><p>8259A 有一个非常重要的机制——当它把一个中断发给 CPU 之后，它会&quot;记住&quot;这个中断正在被处理，在收到 EOI（End Of Interrupt）信号之前，同优先级和更低优先级的中断都不会被转发给 CPU。这意味着中断处理函数在结束之前必须显式地给 PIC 发一个 EOI，告诉它&quot;这个中断我已经处理完了，你可以接收下一个了&quot;。</p><p>EOI 的发送方式是往 PIC 的 Command 端口写 <code>0x20</code>。对于来自 Slave PIC（IRQ8-15）的中断，需要先给 Slave 发 EOI，再给 Master 发 EOI——因为 Master 是通过 IRQ2 收到 Slave 的级联信号的，如果只给 Slave 发了 EOI 而不给 Master 发，Master 就一直认为 IRQ2 上的中断还没处理完，后续所有中断都会被阻塞。</p><p>这个 EOI 机制是一个极其常见的坑——如果你忘了发 EOI，或者 EOI 发错了顺序，症状就是&quot;中断只来一次就再也不来了&quot;。这种情况很容易被误认为是 PIC 配置错误或者 IDT 注册错误，但实际原因只是忘了签收。</p><hr><h2 id="动手实现" tabindex="-1">动手实现 <a class="header-anchor" href="#动手实现" aria-label="Permalink to &quot;动手实现&quot;">​</a></h2><h3 id="第一步——pic-驱动头文件-端口常量、icw-常量、class-封装" tabindex="-1">第一步——PIC 驱动头文件：端口常量、ICW 常量、class 封装 <a class="header-anchor" href="#第一步——pic-驱动头文件-端口常量、icw-常量、class-封装" aria-label="Permalink to &quot;第一步——PIC 驱动头文件：端口常量、ICW 常量、class 封装&quot;">​</a></h3><p><strong>目标</strong>：创建 PIC 驱动的 C++ 头文件，用命名空间常量定义 PIC 的 I/O 端口和 ICW 位域，用 class 封装 PIC 的全部操作（init、send_eoi、mask、unmask、disable_all）。</p><p><strong>设计思路</strong>：我们这一章的 PIC 设计全部用 static 方法——因为系统里只有一对 8259A PIC 芯片，不需要实例化。这和上一章 GDT 的 <code>g_gdt</code> 全局实例不太一样，PIC 没有需要存储在实例里的状态（除了两个 offset 值，它们用 static 成员变量就够了）。</p><p><strong>实现约束</strong>：</p><p>头文件需要包含以下组成部分，全部放在 <code>cinux::arch</code> 命名空间下：</p><ol><li><p>一个名为 <code>PicPort</code> 的命名空间，定义四个 <code>constexpr uint16_t</code> 常量：Master PIC 的 Command 端口 0x20、Data 端口 0x21，Slave PIC 的 Command 端口 0xA0、Data 端口 0xA1。这些是 8259A 的标准 I/O 端口地址，从 IBM PC 时代就没变过。</p></li><li><p>一个名为 <code>PicICW</code> 的命名空间，定义 ICW 相关的位域常量。其中 <code>ICW1_INIT = 0x10</code>（bit 4 = 进入初始化模式）和 <code>ICW1_ICW4 = 0x01</code>（bit 0 = 需要 ICW4）分开定义，使用时用 <code>|</code> 组合成 <code>0x11</code>。<code>ICW4_8086 = 0x01</code> 选择 8086 模式。这些分开定义是为了让代码的每一位含义一目了然，而不是面对魔法数字去猜。</p></li><li><p>一个 <code>PIC</code> class，提供六个 static 方法：<code>init</code>（接受两个 uint8_t 参数设置 master/slave offset，默认 0x20/0x28）、<code>send_eoi</code>（接受 uint8_t irq 参数）、<code>mask</code>、<code>unmask</code>、<code>disable_all</code>、<code>master_offset</code>、<code>slave_offset</code>。private 部分有两个 static uint8_t 成员变量存储 offset。</p></li></ol><p>注意 <code>PicICW</code> 命名空间中不仅定义了本章会用到的常量（<code>ICW1_INIT</code>、<code>ICW1_ICW4</code>、<code>ICW4_8086</code>），还定义了一些备选功能的位域常量——<code>ICW1_SINGLE = 0x02</code>（单芯片模式，我们不用，因为有两片 PIC）、<code>ICW4_AUTO_EOI = 0x02</code>（自动 EOI 模式，我们不选，原因在后面设计决策中讨论）。列出这些备选常量的目的是让头文件成为自文档化的参考——读者不需要去查 8259A datasheet 就能知道这个芯片还支持什么功能。</p><p>文件路径：<code>kernel/arch/x86_64/pic.hpp</code></p><p><strong>踩坑预警</strong>：ICW1 的各个 bit 是独立的控制位，必须分开定义然后 OR 组合，不要直接写裸的 <code>0x11</code>。另外 <code>init</code> 的参数必须满足&quot;是 8 的倍数&quot;这个约束——0x20 和 0x28 都满足，但如果你传了 0x21 这样的值，8259A 会在低 3 位上做 IRQ 编号替换，向量号就不对了。</p><p><strong>验证</strong>：此步完成后编译应该通过，但还没有可运行的输出。可以用 <code>cmake --build build -j$(nproc)</code> 验证编译无误。</p><h3 id="第二步——pic-驱动实现-icw1-4-初始化序列、eoi、mask-unmask" tabindex="-1">第二步——PIC 驱动实现：ICW1-4 初始化序列、EOI、mask/unmask <a class="header-anchor" href="#第二步——pic-驱动实现-icw1-4-初始化序列、eoi、mask-unmask" aria-label="Permalink to &quot;第二步——PIC 驱动实现：ICW1-4 初始化序列、EOI、mask/unmask&quot;">​</a></h3><p><strong>目标</strong>：实现 PIC 的所有方法。init() 发送完整的 ICW1-ICW4 序列并附带 io_wait() 延迟；send_eoi() 处理 Master/Slave 双发逻辑；mask()/unmask() 通过 read-modify-write 操作 IMR 寄存器。</p><p><strong>设计思路</strong>：</p><p>init() 函数的开头先把两个 PIC 当前的 IMR（Interrupt Mask Register）值读出来保存在局部变量里。为什么要保存？因为 ICW 序列写入的过程中会暂时覆盖 IMR 的值，如果我们不保存和恢复，init() 执行完毕后所有 IRQ 的屏蔽状态会被搞乱。然后依次发送 ICW1（command 端口，0x11）、ICW2（data 端口，master offset/slave offset）、ICW3（data 端口，Master 写 0x04 Slave 写 0x02）、ICW4（data 端口，0x01）。每次写入后跟一个 io_wait()。最后恢复保存的 IMR 值。</p><p>send_eoi() 的逻辑很直接：参数是 IRQ 号（0-15），不是 INT 向量号。如果 irq &gt;= 8 说明来自 Slave PIC，先给 Slave 发 EOI 再给 Master 发；否则只给 Master 发。EOI 命令就是往 Command 端口写 0x20。</p><p>unmask() 和 mask() 的实现是对 IMR 的读-改-写操作。IMR 是 8 位寄存器，每位对应一条 IRQ 线，bit=1 屏蔽，bit=0 允许。对于 Master PIC 的 IRQ0-7 直接操作对应位，对于 Slave PIC 的 IRQ8-15 先把 IRQ 编号减 8 得到位偏移再操作。unmask 用 <code>&amp; ~(1u &lt;&lt; n)</code> 清零对应位，mask 用 <code>| (1u &lt;&lt; n)</code> 置位对应位。</p><p>disable_all() 最简单——直接往两个 data 端口写 0xFF，屏蔽全部 16 条 IRQ 线。</p><p>文件路径：<code>kernel/arch/x86_64/pic.cpp</code></p><p><strong>踩坑预警</strong>：ICW3 的两个值含义完全不同但都和数字 2 有关。Master 写 0x04 是一个位图（bit 2 置 1 表示 IRQ2 上有 Slave），Slave 写 0x02 是一个编号（级联身份 ID = 2）。写反了级联就断了。另外 io_wait() 不能省略，虽然 QEMU 不严格要求但保持一致性是好习惯。</p><p>关于 IMR 的保存和恢复，这里有一个常见的问题：为什么不直接在 init() 末尾调用 <code>disable_all()</code> 把所有 IRQ 屏蔽掉，而要费劲保存和恢复之前的值？原因有两方面。第一，调用方可能在 init() 之前就已经通过 BIOS 设置了特定的屏蔽位（比如 BIOS 可能已经 unmask 了 IRQ0 和 IRQ1），直接 <code>disable_all()</code> 会破坏这些设置。第二，保存恢复的语义更清晰——init() 做的事情是&quot;重新初始化 PIC 并保持屏蔽状态不变&quot;，而不是&quot;重新初始化 PIC 并屏蔽所有 IRQ&quot;。后者是一种策略决策，不应该隐藏在 init() 里。</p><p><strong>验证</strong>：编译通过即可。可以用 <code>cmake --build build -j$(nproc)</code> 验证。</p><hr><h2 id="深入理解-为什么-pic-初始化必须重映射" tabindex="-1">深入理解：为什么 PIC 初始化必须重映射 <a class="header-anchor" href="#深入理解-为什么-pic-初始化必须重映射" aria-label="Permalink to &quot;深入理解：为什么 PIC 初始化必须重映射&quot;">​</a></h2><p>很多教程在讲 PIC 初始化时会直接给出代码，但对&quot;为什么要重映射&quot;这个问题往往一笔带过。让我们详细拆解一下。</p><p>Intel 在设计 x86 保护模式时，把 INT 0x00 到 INT 0x1F（0-31）保留给了 CPU 异常。这些异常由 CPU 内部条件触发——比如除零（#DE, INT 0）、缺页（#PF, INT 14）、一般保护错误（#GP, INT 13）。当这些异常发生时，CPU 会自动将错误码压栈并跳转到对应的 IDT 条目。</p><p>IBM 在设计 PC/AT 时选择了 8259A 作为中断控制器，并把 Master PIC 的向量基址设为 0x08。这意味着 IRQ0（定时器）被映射到 INT 0x08，而 INT 0x08 正好是 #DF（Double Fault）。如果不去重映射，定时器中断每次到来，CPU 都会以为发生了 Double Fault——而你的 #DF handler 很可能只是打印一条错误信息然后 halt，于是内核就卡死了。</p><p>更微妙的是 IRQ13（协处理器错误）和 INT 0x0D（#GP）的重叠——如果 FPU 产生了一个错误中断，CPU 会跳到 #GP handler，handler 看到的是一个莫名其妙的&quot;一般保护错误&quot;，完全无法诊断。</p><p>重映射到 0x20-0x2F 的选择不是随意的。Intel 保留了 0x00-0x1F 给 CPU 异常（实际上只用了 0x00-0x1E，0x1F 是保留的），从 0x20（32）开始就是用户可用的向量号区域。Master PIC 基址 0x20 覆盖 IRQ0-7（INT 0x20-0x27），Slave PIC 基址 0x28 覆盖 IRQ8-15（INT 0x28-0x2F），16 个向量号正好连成一片，中间没有间隙。这个布局已经成为 x86 OS 开发的标准约定。</p><hr><h2 id="本篇小结" tabindex="-1">本篇小结 <a class="header-anchor" href="#本篇小结" aria-label="Permalink to &quot;本篇小结&quot;">​</a></h2><p>本篇介绍了 8259A PIC 的硬件架构、BIOS 默认映射与 CPU 异常向量的冲突问题、ICW1-ICW4 四步初始化序列的含义、以及 EOI 机制的原理。动手部分完成了 PIC 驱动的头文件和实现——<code>PIC::init()</code> 完成 IRQ 重映射，<code>PIC::send_eoi()</code> 处理中断结束签收，<code>PIC::mask()</code>/<code>unmask()</code> 控制单条 IRQ 线的开关。</p><p>下一篇我们将在此基础上构建 PIT 定时器驱动，配置 Channel 0 为 100 Hz 方波模式，编写 IRQ0 handler 来统计 tick 和打印 uptime。</p><h2 id="参考资料" tabindex="-1">参考资料 <a class="header-anchor" href="#参考资料" aria-label="Permalink to &quot;参考资料&quot;">​</a></h2><p><strong>Intel 手册</strong>：</p><ul><li>Intel 64 and IA-32 Architectures SDM, Volume 3A, Section 6.2 -- Exception and Interrupt Vectors</li></ul><p><strong>OSDev Wiki</strong>：</p><ul><li><a href="https://wiki.osdev.org/8259_PIC" target="_blank" rel="noreferrer">8259 PIC</a> -- PIC 重映射、ICW 序列、EOI 机制</li></ul>`,61)])])}const C=s(l,[["render",i]]);export{u as __pageData,C as default};
